import{_ as t,o as a,c as r,a3 as o}from"./chunks/framework.CjquFG0V.js";const y=JSON.parse('{"title":"30. Recovery Of Overpayments","description":"","frontmatter":{"title":"30. Recovery Of Overpayments","eba":"Health Allied & Managers Admin 2021-2025","topics":["allowances","wages","disputes","preliminary"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/wages/30-recovery-of-overpayments.md","filePath":"ebas/has-managers-admin/common-terms/wages/30-recovery-of-overpayments.md"}'),n={name:"ebas/has-managers-admin/common-terms/wages/30-recovery-of-overpayments.md"};function s(i,e,p,m,l,c){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="_30-recovery-of-overpayments" tabindex="-1">30. Recovery Of Overpayments <a class="header-anchor" href="#_30-recovery-of-overpayments" aria-label="Permalink to &quot;30. Recovery Of Overpayments&quot;">​</a></h1><p><strong>30.1</strong> Details of overpayment Where a Health Service determines that an overpayment has occurred, the Health Service shall provide, in writing, to the relevant Employee:</p><p><strong>(a)</strong> the total amount of overpayment,</p><p><strong>(b)</strong> the reason, if any, for the overpayment (i.e. incorrect application of an allowance),</p><p><strong>(c)</strong> when the overpayments have occurred,</p><p><strong>(d)</strong> the scope to enter into a repayment arrangement within the limits set by the Financial Management Act 1994 (currently one tenth of the salary or wages, before any deductions),</p><p><strong>30.2</strong> Dispute Either the Health Service or Employee may refer a dispute about an overpayment, including but not limited to the quantum of the overpayment and/or how it is to be repaid, to the Dispute Resolution clause of this Agreement.</p><p><strong>30.3</strong> Other rights Nothing in this clause affects the rights or obligations or either party under the Financial Management Act 1994 including but not limited to:</p><p><strong>(a)</strong> The Employee’s right to apply to the relevant Minister for the weekly amount of the deductions to be reduced, and</p><p><strong>(b)</strong> The Employee’s right to apply in writing to the relevant Minister to be relieved from all or any of the liability with respect to the repayment of the overpayment.</p><p>Plain language terms: overpayment, wage recovery, clawback.</p>',11)])])}const g=t(n,[["render",s]]);export{y as __pageData,g as default};
